import './App.css';
import Navbar from './componentes/navbar';
import Footer from './componentes/footer';
import Abogadas from './componentes/abogadas';
import july from './src/assets/july.jpg';
function App() {
  return (
    <div className="App">
    <header className="header">
      <Navbar />
    </header>
      <div className="abogadas-container">
        <Abogadas 
          nombre="Abogada 1"
          imagen={july.png}
          especialidades={["Derecho Civil", "Derecho Penal"]}
        />
        <Abogadas
          nombre="Abogada 2"
          imagen={july.png}
          especialidades={["Derecho Corporativo", "Derecho de Familia"]}
        />
      </div>
      <footer>
        <Footer />
      </footer>

    </div>
  );
}

export default App;
